  constructor () {
    keys := [];
    values := [];
  }

  method EnsureTotalCapacity(n: nat) returns (r: Result<bool>)
    modifies this
  {
    r := Ok(true);
  }

  method SetEntriesLen(n: nat)
    modifies this
  {
    keys := [];
    values := [];
  }

  method PutAssumeCapacity(k: K, v: V)
    modifies this
  {
    keys := keys + [k];
    values := values + [v];
  }

  method Put(k: K, v: V) returns (r: Result<bool>)
    modifies this
  {
