function V2FormatVersion(): int { 2 }
function MetaHashLen(): nat { 8 }

function HasWorkspacePackageIdsTag(): int { 0x434150734B724F77 }
function HasTrustedDependenciesTag(): int { 0x6444457453755274 }
function HasEmptyTrustedDependenciesTag(): int { 0x5455735572547045 }
function HasOverridesTag(): int { 0x734469725265566F }
function HasPatchedDependenciesTag(): int { 0x4464456843744170 }
function HasCatalogsTag(): int { 0x53674F6C41634163 }
function HasConfigVersionTag(): int { 0x4E73527647664E63 }

method PackageSerializerLoad(stream: Stream, total_buffer_size: nat, migrate_from_v2: bool) returns (r: Result<PackageLoadResult>)
  modifies stream
{
  var plr := new PackageLoadResult();
  r := Ok(plr);
}

method BuffersLoad(stream: Stream, log: Log, manager: Option<PackageManager>) returns (r: Result<Buffers>)
  modifies stream
{
  var b := new Buffers();
  r := Ok(b);
}

method ReadArray<T>(stream: Stream) returns (r: Result<seq<T>>)
  modifies stream
{
  r := Ok([]);
}

function MigrateVersion(old: SemverVersionV2): SemverVersion { old }
function ToDependency(ext: DependencyExternal): DependencyExternal { ext }
function ConfigVersionFromInt(x: int): Option<ConfigVersion> { if 0 <= x then Some(x) else None }

method Load(lockfile: Lockfile, stream: Stream, log: Log, manager: Option<PackageManager>) returns (r: Result<SerializerLoadResult>)
  modifies lockfile, stream, lockfile.packages, lockfile.buffers, lockfile.workspace_versions,
           lockfile.workspace_paths, lockfile.overrides, lockfile.overrides.map,
           lockfile.patched_dependencies, lockfile.catalogs, lockfile.catalogs.default,
           lockfile.catalogs.groups, lockfile.package_index
{
  var res := new SerializerLoadResult();
  var header_read := stream.ReadAll(|HeaderBytes()|);
  if header_read.Err? { r := Err(header_read.error); return; }
  var header_buf := header_read.value;

  if header_buf != HeaderBytes() {
    r := Err("InvalidLockfile");
    return;
  }

  var migrate_from_v2 := false;
  var format_read := stream.ReadU32LE();
  if format_read.Err? { r := Err(format_read.error); return; }
  var format := format_read.value;
  if format > CurrentFormatVersion() {
    r := Err("Unexpected lockfile version");
    return;
  }

  if format < CurrentFormatVersion() {
    if format != V2FormatVersion() {
      r := Err("Outdated lockfile version");
      return;
    }

    migrate_from_v2 := true;
  }

  lockfile.format := CurrentFormatVersion();

  var meta_hash_read := stream.ReadAll(MetaHashLen());
  if meta_hash_read.Err? { r := Err(meta_hash_read.error); return; }
  lockfile.meta_hash := meta_hash_read.value;

  var total_buffer_size_read := stream.ReadU64LE();
  if total_buffer_size_read.Err? { r := Err(total_buffer_size_read.error); return; }
  var total_buffer_size := total_buffer_size_read.value;
  if total_buffer_size > |stream.buffer| {
    r := Err("Lockfile is missing data");
    return;
  }

  var packages_load_result_read := PackageSerializerLoad(stream, total_buffer_size as nat, migrate_from_v2);
  if packages_load_result_read.Err? { r := Err(packages_load_result_read.error); return; }
  var packages_load_result := packages_load_result_read.value;

  lockfile.packages := packages_load_result.list;

  res.packages_need_update := packages_load_result.needs_update;
  res.migrated_from_lockb_v2 := migrate_from_v2;

  var buffers_read := BuffersLoad(stream, log, manager);
  if buffers_read.Err? { r := Err(buffers_read.error); return; }
  lockfile.buffers := buffers_read.value;

  var end_read := stream.ReadU64LE();
  if end_read.Err? { r := Err(end_read.error); return; }
  if end_read.value != 0 {
    r := Err("Lockfile is malformed (expected 0 at the end)");
    return;
  }

  var has_workspace_name_hashes := false;
  {
    var remaining_in_buffer := if total_buffer_size - stream.pos as int > 0 then total_buffer_size - stream.pos as int else 0;

    if remaining_in_buffer > 8 && total_buffer_size <= |stream.buffer| {
      var next_num_read := stream.ReadU64LE();
      if next_num_read.Err? { r := Err(next_num_read.error); return; }
      var next_num := next_num_read.value;
      if next_num == HasWorkspacePackageIdsTag() {
        var workspace_package_name_hashes_read := ReadArray<PackageNameHash>(stream);
        if workspace_package_name_hashes_read.Err? { r := Err(workspace_package_name_hashes_read.error); return; }
        var workspace_package_name_hashes := workspace_package_name_hashes_read.value;

        var workspace_versions_list: seq<SemverVersion>;
        if !migrate_from_v2 {
          var workspace_versions_list_read := ReadArray<SemverVersion>(stream);
          if workspace_versions_list_read.Err? { r := Err(workspace_versions_list_read.error); return; }
          workspace_versions_list := workspace_versions_list_read.value;
        } else {
          var old_versions_list_read := ReadArray<SemverVersionV2>(stream);
          if old_versions_list_read.Err? { r := Err(old_versions_list_read.error); return; }
          var old_versions_list := old_versions_list_read.value;
          var versions_list: seq<SemverVersion> := [];
          var i := 0;
          while i < |old_versions_list|
            decreases |old_versions_list| - i
          {
            versions_list := versions_list + [MigrateVersion(old_versions_list[i])];
            i := i + 1;
          }
          workspace_versions_list := versions_list;
        }

        if |workspace_package_name_hashes| != |workspace_versions_list| {
          r := Err("InvalidLockfile");
          return;
        }

        var ec := lockfile.workspace_versions.EnsureTotalCapacity(|workspace_versions_list|);
        if ec.Err? { r := Err(ec.error); return; }
        lockfile.workspace_versions.keys := workspace_package_name_hashes;
        lockfile.workspace_versions.values := workspace_versions_list;
        var ri := lockfile.workspace_versions.ReIndex();
        if ri.Err? { r := Err(ri.error); return; }

        var workspace_paths_hashes_read := ReadArray<PackageNameHash>(stream);
        if workspace_paths_hashes_read.Err? { r := Err(workspace_paths_hashes_read.error); return; }
        var workspace_paths_hashes := workspace_paths_hashes_read.value;
        var workspace_paths_strings_read := ReadArray<SemverString>(stream);
        if workspace_paths_strings_read.Err? { r := Err(workspace_paths_strings_read.error); return; }
        var workspace_paths_strings := workspace_paths_strings_read.value;

        if |workspace_paths_hashes| != |workspace_paths_strings| {
          r := Err("InvalidLockfile");
          return;
        }

        var wpc := lockfile.workspace_paths.EnsureTotalCapacity(|workspace_paths_strings|);
        if wpc.Err? { r := Err(wpc.error); return; }
        lockfile.workspace_paths.keys := workspace_paths_hashes;
        lockfile.workspace_paths.values := workspace_paths_strings;
        var wpri := lockfile.workspace_paths.ReIndex();
        if wpri.Err? { r := Err(wpri.error); return; }
      } else {
        stream.pos := stream.pos - 8;
      }
    }
  }

  {
    var remaining_in_buffer := if total_buffer_size - stream.pos as int > 0 then total_buffer_size - stream.pos as int else 0;

    if remaining_in_buffer >= 8 && total_buffer_size <= |stream.buffer| {
      var next_num_read := stream.ReadU64LE();
      if next_num_read.Err? { r := Err(next_num_read.error); return; }
      var next_num := next_num_read.value;
      if remaining_in_buffer > 8 && next_num == HasTrustedDependenciesTag() {
        var trusted_dependencies_hashes_read := ReadArray<int>(stream);
        if trusted_dependencies_hashes_read.Err? { r := Err(trusted_dependencies_hashes_read.error); return; }
        var trusted_dependencies_hashes := trusted_dependencies_hashes_read.value;

        var td := new TrustedDependencies();
        lockfile.trusted_dependencies := Some(td);
        var tdc := td.EnsureTotalCapacity(|trusted_dependencies_hashes|);
        if tdc.Err? { r := Err(tdc.error); return; }
        td.keys := trusted_dependencies_hashes;
        var tdri := td.ReIndex();
        if tdri.Err? { r := Err(tdri.error); return; }
      } else if next_num == HasEmptyTrustedDependenciesTag() {
        var empty_td := new TrustedDependencies();
        lockfile.trusted_dependencies := Some(empty_td);
      } else {
        stream.pos := stream.pos - 8;
      }
    }
  }

  {
    var remaining_in_buffer := if total_buffer_size - stream.pos as int > 0 then total_buffer_size - stream.pos as int else 0;

    if remaining_in_buffer > 8 && total_buffer_size <= |stream.buffer| {
      var next_num_read := stream.ReadU64LE();
      if next_num_read.Err? { r := Err(next_num_read.error); return; }
      var next_num := next_num_read.value;
      if next_num == HasOverridesTag() {
        var overrides_name_hashes_read := ReadArray<PackageNameHash>(stream);
        if overrides_name_hashes_read.Err? { r := Err(overrides_name_hashes_read.error); return; }
        var overrides_name_hashes := overrides_name_hashes_read.value;
        var omc := lockfile.overrides.map.EnsureTotalCapacity(|overrides_name_hashes|);
        if omc.Err? { r := Err(omc.error); return; }
        var override_versions_external_read := ReadArray<DependencyExternal>(stream);
        if override_versions_external_read.Err? { r := Err(override_versions_external_read.error); return; }
        var override_versions_external := override_versions_external_read.value;
        var i := 0;
        while i < |overrides_name_hashes| && i < |override_versions_external|
          decreases |overrides_name_hashes| - i
        {
          lockfile.overrides.map.PutAssumeCapacity(overrides_name_hashes[i], ToDependency(override_versions_external[i]));
          i := i + 1;
        }
      } else {
        stream.pos := stream.pos - 8;
      }
    }
  }

  {
    var remaining_in_buffer := if total_buffer_size - stream.pos as int > 0 then total_buffer_size - stream.pos as int else 0;

    if remaining_in_buffer > 8 && total_buffer_size <= |stream.buffer| {
      var next_num_read := stream.ReadU64LE();
      if next_num_read.Err? { r := Err(next_num_read.error); return; }
      var next_num := next_num_read.value;
      if next_num == HasPatchedDependenciesTag() {
        var patched_hashes_read := ReadArray<PackageNameAndVersionHash>(stream);
        if patched_hashes_read.Err? { r := Err(patched_hashes_read.error); return; }
        var patched_hashes := patched_hashes_read.value;
        var pc := lockfile.patched_dependencies.EnsureTotalCapacity(|patched_hashes|);
        if pc.Err? { r := Err(pc.error); return; }
        var patched_paths_read := ReadArray<PatchedDep>(stream);
        if patched_paths_read.Err? { r := Err(patched_paths_read.error); return; }
        var patched_paths := patched_paths_read.value;
        var i := 0;
        while i < |patched_hashes| && i < |patched_paths|
          decreases |patched_hashes| - i
        {
          lockfile.patched_dependencies.PutAssumeCapacity(patched_hashes[i], patched_paths[i]);
          i := i + 1;
        }
      } else {
        stream.pos := stream.pos - 8;
      }
    }
  }

  {
    var remaining_in_buffer := if total_buffer_size - stream.pos as int > 0 then total_buffer_size - stream.pos as int else 0;

    if remaining_in_buffer > 8 && total_buffer_size <= |stream.buffer| {
      var next_num_read := stream.ReadU64LE();
      if next_num_read.Err? { r := Err(next_num_read.error); return; }
      var next_num := next_num_read.value;
      if next_num == HasCatalogsTag() {
        lockfile.catalogs := new Catalogs();
        var default_dep_names_read := ReadArray<SemverString>(stream);
        if default_dep_names_read.Err? { r := Err(default_dep_names_read.error); return; }
        var default_dep_names := default_dep_names_read.value;
        var default_deps_read := ReadArray<DependencyExternal>(stream);
        if default_deps_read.Err? { r := Err(default_deps_read.error); return; }
        var default_deps := default_deps_read.value;
        var dc := lockfile.catalogs.default.EnsureTotalCapacity(|default_deps|);
        if dc.Err? { r := Err(dc.error); return; }
        var i := 0;
        while i < |default_dep_names| && i < |default_deps|
          decreases |default_dep_names| - i
        {
          lockfile.catalogs.default.PutAssumeCapacity(default_dep_names[i], ToDependency(default_deps[i]));
          i := i + 1;
        }

        var catalog_names_read := ReadArray<SemverString>(stream);
        if catalog_names_read.Err? { r := Err(catalog_names_read.error); return; }
        var catalog_names := catalog_names_read.value;
        var gc := lockfile.catalogs.groups.EnsureTotalCapacity(|catalog_names|);
        if gc.Err? { r := Err(gc.error); return; }
        var ci := 0;
        while ci < |catalog_names|
          decreases |catalog_names| - ci
        {
          var catalog_dep_names_read := ReadArray<SemverString>(stream);
          if catalog_dep_names_read.Err? { r := Err(catalog_dep_names_read.error); return; }
          var catalog_dep_names := catalog_dep_names_read.value;
          var catalog_deps_read := ReadArray<DependencyExternal>(stream);
          if catalog_deps_read.Err? { r := Err(catalog_deps_read.error); return; }
          var catalog_deps := catalog_deps_read.value;
          var group := new HashMap<SemverString, DependencyExternal>();
          var gdc := group.EnsureTotalCapacity(|catalog_deps|);
          if gdc.Err? { r := Err(gdc.error); return; }
          var di := 0;
          while di < |catalog_dep_names| && di < |catalog_deps|
            decreases |catalog_dep_names| - di
          {
            group.PutAssumeCapacity(catalog_dep_names[di], ToDependency(catalog_deps[di]));
            di := di + 1;
          }
          if catalog_names[ci] == [] {
            lockfile.catalogs.default := group;
          } else {
            lockfile.catalogs.groups.PutAssumeCapacity(catalog_names[ci], group);
          }
          ci := ci + 1;
        }
      } else {
        stream.pos := stream.pos - 8;
      }
    }
  }

  {
    var remaining_in_buffer := if total_buffer_size - stream.pos as int > 0 then total_buffer_size - stream.pos as int else 0;

    if remaining_in_buffer > 8 && total_buffer_size <= |stream.buffer| {
      var next_num_read := stream.ReadU64LE();
      if next_num_read.Err? { r := Err(next_num_read.error); return; }
      var next_num := next_num_read.value;
      if next_num == HasConfigVersionTag() {
        var cv_read := stream.ReadU64LE();
        if cv_read.Err? { r := Err(cv_read.error); return; }
        var config_version := ConfigVersionFromInt(cv_read.value);
        if config_version.None? {
          r := Err("InvalidLockfile");
          return;
        }
        lockfile.saved_config_version := config_version;
      }
    }
  }

  lockfile.scratch := new Scratch.Init();
  lockfile.package_index := new PackageIndexMap();
  lockfile.string_pool := new StringPool();
  var pic := lockfile.package_index.EnsureTotalCapacity(|lockfile.packages.name_hashes|);
  if pic.Err? { r := Err(pic.error); return; }

  if !has_workspace_name_hashes {
    var len := |lockfile.packages.name_hashes|;
    var id := 0;
    while id < len
      decreases len - id
    {
      var name_hash := lockfile.packages.name_hashes[id];
      var resolution := lockfile.packages.resolutions[id];
      var gid := lockfile.GetOrPutID(id, name_hash);
      if gid.Err? { r := Err(gid.error); return; }

      match resolution.tag
      case Workspace =>
        var wpp := lockfile.workspace_paths.Put(name_hash, resolution.workspaceValue);
        if wpp.Err? { r := Err(wpp.error); return; }
      case _ =>
      id := id + 1;
    }
  } else {
    var len := |lockfile.packages.name_hashes|;
    var id := 0;
    while id < len
      decreases len - id
    {
      var name_hash := lockfile.packages.name_hashes[id];
      var gid := lockfile.GetOrPutID(id, name_hash);
      if gid.Err? { r := Err(gid.error); return; }
      id := id + 1;
    }
  }

  r := Ok(res);
}

method SanityCheck_Load_InvalidHeader()
{
  var lockfile := new Lockfile();
  var stream := new Stream([0,1,2]);
  var log := new Log();
  var result := Load(lockfile, stream, log, None);
  assert result == Err("InvalidLockfile");
}

